package br.com.dio.util;import java.util.ArrayList;import java.util.Collections;import java.util.List;import java.util.Random;public class SudokuGenerator {private static final int SIZE = 9;private static final int SUBGRID = 3;private Random rand = new Random();public int[][] generateFull() {int[][] b = new int[9][9];fillBoard(b);return b;}private boolean fillBoard(int[][] b) {for (int r = 0; r < 9; r++) {for (int c = 0; c < 9; c++) {if (b[r][c] == 0) {List<Integer> nums = getShuffled();for (int n : nums) {if (valid(b, r, c, n)) {b[r][c] = n;if (fillBoard(b)) {return true;}b[r][c] = 0;}}return false;}}}return true;}private List<Integer> getShuffled() {List<Integer> nums = new ArrayList();for (int i = 1; i <= 9; i++) {nums.add(i);}Collections.shuffle(nums, this.rand);return nums;}private boolean valid(int[][] b, int row, int col, int num) {for (int i = 0; i < 9; i++) {if (b[row][i] == num) {return false;}}for (int i = 0; i < 9; i++) {if (b[i][col] == num) {return false;}}int br = row - row % 3;int bc = col - col % 3;for (int r = br; r < br + 3; r++) {for (int c = bc; c < bc + 3; c++) {if (b[r][c] == num) {return false;}}}return true;}public int[][] createPuzzle(int filled) {int[][] sol = generateFull();int[][] puz = new int[9][9];for (int i = 0; i < 9; i++) {for (int j = 0; j < 9; j++) {puz[i][j] = sol[i][j];}}List<Integer> pos = new ArrayList();for (int i = 0; i < 81; i++) {pos.add(i);}Collections.shuffle(pos, this.rand);int toRemove = 81 - filled;for (int i = 0; i < toRemove && i < pos.size(); i++) {int p = pos.get(i);puz[p / 9][p % 9] = 0;}return puz;}}